export type modelHubDatasetOptimizationListResponse = (modelHubDatasetOptimizationListResponseSuccess)

export const getModelHubDatasetOptimizationListUrl = (params?: ModelHubDatasetOptimizationListParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/model-hub/dataset-optimization/?${stringifiedParams}` : `/model-hub/dataset-optimization/`
}

