export const getModelHubEvalGroupsListUrl = (params?: ModelHubEvalGroupsListParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/model-hub/eval-groups/?${stringifiedParams}` : `/model-hub/eval-groups/`
}

